const now = new Date();
const d7 = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
return [{ json: { now: now.toISOString(), since7d: d7.toISOString(), runDate: now.toISOString().slice(0, 10) } }];

function rows(nodeName) {
  const out = [];
  for (const it of $(nodeName).all()) {
    const p = it && it.json;
    if (!p) continue;
    if (Array.isArray(p)) { for (const r of p) if (r && typeof r === 'object' && r.id) out.push(r); }
    else if (Array.isArray(p.data)) { for (const r of p.data) if (r && typeof r === 'object' && r.id) out.push(r); }
    else if (typeof p === 'object' && p.id) { out.push(p); }
  }
  return out;
}

const ars = rows('Read AR register');
const crs = rows('Read CR register');
const openTasks = rows('Read open compliance_tasks');
const nowIso = new Date().toISOString();
const nowMs = Date.now();
const runDate = $('Compute Window').first().json.runDate;

// AR/CR health
const arsActive = ars.filter(r => r.status === 'active');
const arsWithoutNumber = arsActive.filter(r => !r.ar_number);
const crsActive = crs.filter(r => r.status === 'active');
const crsWithoutNumber = crsActive.filter(r => !r.cr_number);

// Stale tasks (>5 business days ~= 7 calendar days old, still open)
const FIVE_D = 5 * 24 * 60 * 60 * 1000;
const staleTasks = openTasks.filter(t => {
  const age = t.created_at ? (nowMs - new Date(t.created_at).getTime()) : 0;
  return age > FIVE_D;
});
const criticalTasks = openTasks.filter(t => t.severity === 'critical' || t.severity === 'high');

// Upcoming due dates (14 days)
const FOURTEEN_D = 14 * 24 * 60 * 60 * 1000;
const upcomingDue = openTasks.filter(t => {
  if (!t.due_date) return false;
  const dueMs = new Date(t.due_date).getTime();
  return dueMs > nowMs && (dueMs - nowMs) < FOURTEEN_D;
});

// Severity
let level = 'info';
if (staleTasks.length > 0 || upcomingDue.length > 0) level = 'warn';
if (criticalTasks.length > 0 || arsWithoutNumber.length > 0 || crsWithoutNumber.length > 0) level = 'error';

const summary = {
  run_date: runDate,
  ar_active_count: arsActive.length,
  ar_missing_number_count: arsWithoutNumber.length,
  ar_missing_number_ids: arsWithoutNumber.slice(0, 20).map(r => ({ id: r.id, legal_name: r.legal_name })),
  cr_active_count: crsActive.length,
  cr_missing_number_count: crsWithoutNumber.length,
  cr_missing_number_ids: crsWithoutNumber.slice(0, 20).map(r => ({ id: r.id, legal_name: r.legal_name })),
  open_tasks_count: openTasks.length,
  critical_or_high_tasks: criticalTasks.length,
  stale_tasks_over_5d: staleTasks.length,
  upcoming_due_14d: upcomingDue.length,
  upcoming_due_sample: upcomingDue.slice(0, 10).map(t => ({ id: t.id, title: t.title, due_date: t.due_date })),
  run_at: nowIso,
};

return [{ json: {
  agent_name: 'licensing',
  level,
  message: `licensing_daily digest — ${criticalTasks.length} critical/high open, ${staleTasks.length} stale, ${upcomingDue.length} due within 14d`,
  metadata: { daily_digest: true, summary, run_at: nowIso }
}}];
